kernel_src="""

#include "kernel_operator.h"
#include <cmath>

class KernelCa6k00305Custom {
public:
    __aicore__ inline KernelCa6k00305Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t inputWidth,
                                uint32_t outputWidth, uint32_t kernelSize,
                                uint32_t stride, float invKernelSize,
                                uint32_t tileLength)
    {
        totalLen_ = totalLength;
        inputWidth_ = inputWidth;
        outputWidth_ = outputWidth;
        kernelSize_ = kernelSize;
        stride_ = stride;
        invKernelSize_ = invKernelSize;
        tileLen_ = tileLength;

        xBase_ = (__gm__ float*)x;
        yBase_ = (__gm__ float*)y;
    }

    __aicore__ inline void Process()
    {
        if (outputWidth_ == 0) return;
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t offsetX = blockIdx * inputWidth_;
        uint32_t offsetY = blockIdx * outputWidth_;

        uint32_t curStart = 0;
        while (curStart < outputWidth_) {
            uint32_t curTileLen = outputWidth_ - curStart;
            if (curTileLen > tileLen_) curTileLen = tileLen_;

            uint32_t inputSliceLen = (curTileLen > 1) ? ((curTileLen - 1) * stride_ + kernelSize_) : kernelSize_;
            uint32_t inputOff = curStart * stride_;

            // Allocate local tensors for input and output
            AscendC::LocalTensor<float> inLocal = pipe_.CreateLocalTensor<float>(inputSliceLen);
            AscendC::LocalTensor<float> yLocal = pipe_.CreateLocalTensor<float>(curTileLen);

            // Copy input slice from global memory
            AscendC::GlobalTensor<float> src;
            src.SetGlobalBuffer(xBase_ + offsetX + inputOff, inputSliceLen);
            AscendC::DataCopy(inLocal, src, inputSliceLen);
            pipe_.Barrier();

            // Compute L2 pooling for each output element
            for (uint32_t i = 0; i < curTileLen; ++i) {
                float sum = 0.0f;
                for (uint32_t k = 0; k < kernelSize_; ++k) {
                    float val = inLocal[i * stride_ + k];
                    sum += val * val;
                }
                // Use std::sqrt which is supported on device with appropriate math library
                yLocal[i] = std::sqrt(sum * invKernelSize_);
            }

            // Copy output back to global memory
            AscendC::GlobalTensor<float> dst;
            dst.SetGlobalBuffer(yBase_ + offsetY + curStart, curTileLen);
            AscendC::DataCopy(dst, yLocal, curTileLen);
            pipe_.Barrier();

            curStart += curTileLen;
        }
    }

private:
    AscendC::TPipe pipe_;
    __gm__ float* xBase_;
    __gm__ float* yBase_;

    uint32_t totalLen_;
    uint32_t inputWidth_;
    uint32_t outputWidth_;
    uint32_t kernelSize_;
    uint32_t stride_;
    float invKernelSize_;
    uint32_t tileLen_;
};

extern "C" __global__ __aicore__ void ca6k_00305_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00305Custom op;
    op.Init(x, y,
            tiling_data.totalLength,
            tiling_data.inputWidth,
            tiling_data.outputWidth,
            tiling_data.kernelSize,
            tiling_data.stride,
            tiling_data.invKernelSize,
            tiling_data.tileLength);
    op.Process();
}
